"""
Seed data for CET-4/6 English exam system - Expanded
"""
import sqlite3

def seed_cet_exam(conn):
    """Seed CET-4/6 English exam data"""
    count = conn.execute("SELECT COUNT(*) FROM sqlite_master WHERE type='table' AND name='cet_exam'").fetchone()[0]
    if count == 0:
        conn.execute("""
            CREATE TABLE IF NOT EXISTS cet_exam (
                id INTEGER PRIMARY KEY AUTOINCREMENT,
                exam_type TEXT NOT NULL,
                section TEXT NOT NULL,
                title TEXT NOT NULL,
                content TEXT NOT NULL,
                answer TEXT,
                difficulty TEXT DEFAULT 'Medium',
                created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP
            )
        """)
    
    if conn.execute("SELECT COUNT(*) FROM cet_exam").fetchone()[0] >= 100:
        return
    
